		PostProcessorConfiguration postProcess = this.spring.getContext().getBean(PostProcessorConfiguration.class);
		AbstractAuthenticationProcessingFilter filter = postProcess.webauthnFilter;
		Object authenticationManager = ReflectionTestUtils.getField(filter, "authenticationManager");
		List<?> providers = (List<?>) ReflectionTestUtils.getField(authenticationManager, "providers");
