		JsonNode parsedResponse = mapper.readTree(response);

		assertThat(parsedResponse.get("rp").get("id").asText()).isEqualTo("example.com");
		assertThat(parsedResponse.get("rp").get("name").asText()).isEqualTo("Test RP Name");
	}

